import{_ as e,o as t,c as a,a0 as l}from"./chunks/framework.CSGB4SNl.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"mju-ai-server/README.md","filePath":"mju-ai-server/README.md"}'),r={name:"mju-ai-server/README.md"};function o(s,i,n,h,p,u){return t(),a("div",null,[...i[0]||(i[0]=[l('<h1 align="center" style="margin:30px 0 30px;font-weight:bold;">RuoYi v3.9.0</h1><h4 align="center">基于SpringBoot+Vue前后端分离的Java快速开发框架</h4><p align="center"><a href="https://gitee.com/y_project/RuoYi-Vue/stargazers"><img src="https://gitee.com/y_project/RuoYi-Vue/badge/star.svg?theme=dark"></a><a href="https://gitee.com/y_project/RuoYi-Vue"><img src="https://img.shields.io/badge/RuoYi-v3.9.0-brightgreen.svg"></a><a href="https://gitee.com/y_project/RuoYi-Vue/blob/master/LICENSE"><img src="https://img.shields.io/github/license/mashape/apistatus.svg"></a></p><h2 id="平台简介" tabindex="-1">平台简介 <a class="header-anchor" href="#平台简介" aria-label="Permalink to &quot;平台简介&quot;">​</a></h2><p>若依是一套全部开源的快速开发平台，毫无保留给个人及企业免费使用。</p><ul><li>前端采用Vue、Element UI。</li><li>后端采用Spring Boot、Spring Security、Redis &amp; Jwt。</li><li>权限认证使用Jwt，支持多终端认证系统。</li><li>支持加载动态权限菜单，多方式轻松权限控制。</li><li>高效率开发，使用代码生成器可以一键生成前后端代码。</li></ul><h2 id="内置功能" tabindex="-1">内置功能 <a class="header-anchor" href="#内置功能" aria-label="Permalink to &quot;内置功能&quot;">​</a></h2><ol><li>用户管理：用户是系统操作者，该功能主要完成系统用户配置。</li><li>部门管理：配置系统组织机构（公司、部门、小组），树结构展现支持数据权限。</li><li>岗位管理：配置系统用户所属担任职务。</li><li>菜单管理：配置系统菜单，操作权限，按钮权限标识等。</li><li>角色管理：角色菜单权限分配、设置角色按机构进行数据范围权限划分。</li><li>字典管理：对系统中经常使用的一些较为固定的数据进行维护。</li><li>参数管理：对系统动态配置常用参数。</li><li>通知公告：系统通知公告信息发布维护。</li><li>操作日志：系统正常操作日志记录和查询；系统异常信息日志记录和查询。</li><li>登录日志：系统登录日志记录查询包含登录异常。</li><li>在线用户：当前系统中活跃用户状态监控。</li><li>定时任务：在线（添加、修改、删除)任务调度包含执行结果日志。</li><li>代码生成：前后端代码的生成（java、html、xml、sql）支持CRUD下载 。</li><li>系统接口：根据业务代码自动生成相关的api接口文档。</li><li>服务监控：监视当前系统CPU、内存、磁盘、堆栈等相关信息。</li><li>缓存监控：对系统的缓存信息查询，命令统计等。</li><li>在线构建器：拖动表单元素生成相应的HTML代码。</li><li>连接池监视：监视当前系统数据库连接池状态，可进行分析SQL找出系统性能瓶颈。</li></ol><h2 id="在线体验" tabindex="-1">在线体验 <a class="header-anchor" href="#在线体验" aria-label="Permalink to &quot;在线体验&quot;">​</a></h2><ul><li>admin/admin123</li></ul><p>演示地址：<a href="http://vue.ruoyi.vip" target="_blank" rel="noreferrer">http://vue.ruoyi.vip</a><br> 文档地址：<a href="http://doc.ruoyi.vip" target="_blank" rel="noreferrer">http://doc.ruoyi.vip</a></p>',11)])])}const d=e(r,[["render",o]]);export{m as __pageData,d as default};
